efinition": "发布时间:2025-07-01,评定有效期:3年,颁发机构:广东省工业和信息化厅。企业符合《优质中小企业梯度培育管理暂行办法》中创新型中小企业的认定条件，说明企业在技术、管理、市场和组织等方面具备较强的创新能力和发展潜力。", "labelName": "创新型中小企业", "labelTranslateName": "创新成长型中小企业"}, {"labelCode": "esg_certificate_e", "labelDefinition": "该企业拥有环保绿色相关资质认证。", "labelName": "拥有绿色资质", "labelTranslateName": "拥有绿色资质"}, {"labelCode": "specialized_new_corp", "labelDefinition": "发布时间:2023-12-27,评定有效期:3年,颁发机构:广东省工业和信息化厅。企业符合《优质中小企业梯度培育管理暂行办法》中专精特新企业的认定条件，具有“专业化、精细化、特色化、 新颖化”特征，从事特定细分市场时间达到 2 年以上，企业规模必须符合国家《中小企业划型标准》的规定。", "labelName": "专精特新企业", "labelTranslateName": "专业精深创新企业"}, {"labelCode": "dual_software_certified", "labelDefinition": "评价机构：中国软件行业协会 该认证旨在评估软件企业的软件开发能力和软件服务能力，以及软件产品的质量和安全性。企业拥有软件产品认证和软件企业认证，证明企业拥有“可以获得软件企业资质，提升软件开发和服务水平，增强市场竞争力。", "labelName": "双软认证企业"}, {"labelCode": "absolute_holding_companies", "labelDefinition": "该企业绝对控股2公司，绝对控股是指出资额占有限责任公司资本总额百分之六十七以上或者其持有的股份占股份有限公司股本总额百分之六十七以上。", "labelName": "绝对控股2家公司", "labelTranslateName": "强大经济实力公司"}, {"labelCode": "high_new_tech_corp", "labelDefinition": "发布时间:2023-10-16,评定有效期:3年,颁发机构:全国高新技术企业认定管理工作领导小组办公室。符合《高新技术企业认定管理办法》规定，符合国家重点支持的高新技术领域，持续进行研究开发与技术成果转化，形成企业核心自主知识产权，并以此为基础开展经营活动，在中国境内（不包括港、澳、台地区）注册成立一年以上的居民企业。", "labelName": "高新技术企业", "labelTranslateName": "技术创新卓越企业"}, {"labelCode": "technical_sme", "labelDefinition": "发布时间:2025-09-22,评定有效期:1年,颁发机构:工业和信息化部火炬高技术产业开发中心。科技型中小企业是指依托一定数量的科技人员从事科学技术研究开发活动，取得自主知识产权并将其转化为高新技术产品或服务从而实现可持续发展，在中国境内（不包括港、澳、台地区）注册的中小企业。", "labelName": "科技型中小企业", "labelTranslateName": "科技实力型中小企业"}, {"labelCode": "gov_owned_supplier", "labelDefinition": "经芝麻通过公开数据识别，该企业过去1年曾中标国企单位的招标项目。属于中译语通科技股份有限公司、国网信息通信产业集团有限公司、国网思极网安科技（北京）有限公司供应商，其具有较高的资金实力和经营能力。", "labelName": "国企供应商"}, {"labelCode": "financing_turn", "labelDefinition": "据企业官网或新闻媒体公开数据显示，企业在本年度获投了A轮融资", "labelName": "A轮融资"}, {"labelCode": "new_strategic_industry", "labelDefinition": "该企业申请、授权的专利属于以重大技术突破和重大发展需求为基础，对经济社会全局和长远发展具有重大引领带动作用，知识技术密集、物质资源消耗少、成长潜力大、综合效益好的战略性新兴产业。", "labelName": "战略性新兴领域创新能力", "labelTranslateName": "新兴领域创新企业"}, {"labelCode": "has_patent_invention", "labelDefinition": "该企业拥有一项或多项发明专利。发明专利是指针对产品、方法或其改进所提出的新技术方案。", "labelName": "拥有发明专利"}, {"labelCode": "pat_grant_top", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在电通信技术领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前10%"}, {"labelCode": "tech_layout_leader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "has_patent_green", "labelDefinition": "该企业拥有以绿色低碳技术为发明主题的专利。绿色低碳技术是指通过传统能源清洁利用、节能增效、新能源利用和温室气体捕集利用封存等实现减碳、零碳和负碳效果的有关技术。", "labelName": "拥有绿色低碳技术"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有铸泰科技自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "college_employment_contribution", "labelDefinition": "据公开网络招聘信息显示，该企业在近1年内有发布过大学生就业岗位，助力大学生就业。", "labelName": "大学生就业贡献", "labelTranslateName": "欢迎应届生应聘"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/default/li_portrait_female_006_small.png?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-09 16:30:47", "userInteractionOnlineLabel": 2, "workAreaCode": "040300", "workYear": "5", "workYearString": "3年及以上"}

